import { TZDateMini } from '@date-fns/tz';

import { parseTimeAsTimeValue } from '@dynatrace-sdk/units';
import { getTimezone } from '@dynatrace-sdk/user-preferences';

import type { TimeValue, Timeframe } from '../../../core/types/time.js';
import { getFromToValues } from '../../../forms/forms-core/time/timeParser.js';

/**
 * Check if a date is a given min or max. Returns false if both min and max are missing.
 * @internal
 */
export function dateIsMinMax(
  date?: TimeValue | null,
  min?: string,
  max?: string,
): boolean {
  if ((!min && !max) || !date) {
    return false;
  }
  const timezone = getTimezone();
  const relativeNow = TZDateMini.tz(timezone).getTime();

  const isoDate = parseTimeAsTimeValue(date.value, relativeNow)?.absoluteDate;
  const tempDate = isoDate ? new TZDateMini(isoDate, timezone) : null;

  if (!tempDate) {
    return false;
  }

  const minIsoDate = parseTimeAsTimeValue(min, relativeNow)?.absoluteDate;
  const maxIsoDate = parseTimeAsTimeValue(max, relativeNow)?.absoluteDate;
  const minDate = minIsoDate ? new TZDateMini(minIsoDate, timezone) : null;
  const maxDate = maxIsoDate ? new TZDateMini(maxIsoDate, timezone) : null;

  if (minDate && minDate.getTime() === tempDate.getTime()) {
    return true;
  }

  if (maxDate && maxDate.getTime() === tempDate.getTime()) {
    return true;
  }

  return false;
}

/**
 * Check if the date value is larger than the max value.
 * Returns false if the max or value are not defined.
 * @internal
 */
export function isBiggerThan(candidate?: string, threshold?: string): boolean {
  if (!threshold || !candidate) {
    return false;
  }

  const relativeNow = TZDateMini.tz(getTimezone()).getTime();

  const maxIsoDate = parseTimeAsTimeValue(threshold, relativeNow)?.absoluteDate;
  const valueIsoDate = parseTimeAsTimeValue(
    candidate,
    relativeNow,
  )?.absoluteDate;

  if (!maxIsoDate || !valueIsoDate) {
    return false;
  }

  const maxDate = new TZDateMini(maxIsoDate, getTimezone());
  const valueDate = new TZDateMini(valueIsoDate, getTimezone());

  return valueDate.getTime() > maxDate.getTime();
}

/**
 * Check if the date value is smaller than the min value.
 * Returns false if the value or min are not defined.
 * @internal
 */
export function isSmallerThan(candidate?: string, threshold?: string): boolean {
  if (!threshold || !candidate) {
    return false;
  }

  const relativeNow = TZDateMini.tz(getTimezone()).getTime();

  const minIsoDate = parseTimeAsTimeValue(threshold, relativeNow)?.absoluteDate;
  const valueIsoDate = parseTimeAsTimeValue(
    candidate,
    relativeNow,
  )?.absoluteDate;

  if (!minIsoDate || !valueIsoDate) {
    return false;
  }

  const minDate = new TZDateMini(minIsoDate, getTimezone());
  const valueDate = new TZDateMini(valueIsoDate, getTimezone());

  return valueDate.getTime() < minDate.getTime();
}

/**
 * Check if the value is outside the min - max range.
 * Returns false if the value is not defined, it the from or to values are undefined, or if min and max are both missing.
 * @internal
 */
export function isOutsideRange(
  value?: {
    /** Start of the time frame. */
    from: string | null | TimeValue;
    /** End of the time frame. */
    to: string | null | TimeValue;
  } | null,
  min?: string,
  max?: string,
) {
  if (!value || (!min && !max)) {
    return false;
  }

  const { valueFrom, valueTo } = getFromToValues(value);

  // Min date needs to be larger than from and to in order to be considered
  // outside of the range.
  if (min && (isSmallerThan(valueFrom, min) || isSmallerThan(valueTo, min))) {
    return true;
  }

  // Max date needs to be smaller than from and to in order to be considered
  // outside of the range.
  if (max && (isBiggerThan(valueFrom, max) || isBiggerThan(valueTo, max))) {
    return true;
  }

  return false;
}

/**
 * Type guard function that will check if the value is Timeframe with absoluteDate.
 * @internal
 */
function isTimeframeWithFromAndTo(
  date: {
    from: string | TimeValue | null;
    to: string | TimeValue | null;
  } | null,
): date is Timeframe {
  return (
    typeof date?.from === 'object' &&
    typeof date?.to === 'object' &&
    date.from?.absoluteDate !== '' &&
    date.to?.absoluteDate !== ''
  );
}

/**
 * Type guard function that will check if the value is a Timeframe or from and to String.
 * @internal
 */
export function isTimeframeOrFromToString(
  date: {
    from: string | TimeValue | null;
    to: string | TimeValue | null;
  } | null,
): date is { from: string; to: string } | Timeframe {
  return (
    (typeof date?.from === 'string' && typeof date?.to === 'string') ||
    isTimeframeWithFromAndTo(date)
  );
}
